+
+            let prefix = repo.effective_prefix().to_ascii_lowercase();
+            if !seen_prefixes.insert(prefix.clone()) {
+                return Err(BvrError::InvalidArgument(format!(
+                    "workspace repo[{index}] has duplicate prefix '{prefix}'"
+                )));
+            }
+        }
+
+        if enabled_count == 0 {
