+}
+
+#[derive(Debug, Serialize)]
+struct RobotMetricsOutput {
+    generated_at: String,
+    data_hash: String,
+    output_format: String,
+    version: String,
+    timing: Vec<MetricsTiming>,
+    cache: Vec<MetricsCache>,
+    memory: MetricsMemory,
+}
+
+#[derive(Debug, Serialize)]
+struct MetricsTiming {
+    name: String,
+    count: u64,
+    total_ms: f64,
+    avg_ms: f64,
